sys_script_include.script:
function IsAgenticConversationIdleOrInactive(vConversation)
{
	var grConversation = GetAgenticConversationRecord(vConversation);
	if (IsValidRecord(grConversation) == false)
	{
		return true;
	}

	if (IsAgenticConversationActive(grConversation) == false)
	{
		return true;
	}

	if (grConversation.topic_definition_name == 'system')
	{
		return false;
	}

	if (grConversation.topic_definition_name == '_empty_skill_picker_')
	{
		return true;
	}	
	if (grConversation.topic_definition_name == 'Input Collector - string')
	{
		return true;
	}	
	return false;
}
